UPDATE carts
address_id = #{addressId}, status = #{status}, total_amount = #{totalAmount}, remark = #{remark}, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE cart_items
SET is_deleted = 1, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE cart_id = #{cartId} AND updated_at = #{updatedAt}

UPDATE cart_items
SET quantity = #{quantity}, updated_at = SYSTIMESTAMP
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE cart_items
SET is_deleted = 1, updated_at = SYSTIMESTAMP
WHERE id = #{id} AND updated_at = #{updatedAt}
